// nodes/llmNode.js
import { BaseNode } from './BaseNode';
import { Sparkles } from 'lucide-react';

export const LLMNode = ({ id, data, selected }) => {
  return (
    <BaseNode
      id={id}
      title="LLM"
      icon={Sparkles}
      accentColor="var(--accent-violet)"
      inputs={[
        { id: 'system', label: 'system' },
        { id: 'prompt', label: 'prompt' },
      ]}
      outputs={[{ id: 'response', label: 'response' }]}
      selected={selected}
    >
      <div style={{ fontSize: '13px', color: 'var(--text-secondary)' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '6px', marginBottom: '4px' }}>
          <div style={{ width: 6, height: 6, borderRadius: '50%', background: 'var(--accent-violet)' }} />
          <span style={{ fontWeight: 500, color: 'var(--text-primary)' }}>{data?.model || 'gpt-4o'}</span>
        </div>
        <div style={{ fontSize: '11px', color: 'var(--text-tertiary)' }}>Temp: {data?.temperature || '0.7'}</div>
      </div>
    </BaseNode>
  );
};
